userDefinedLinkHintCss:
div > .vimiumHintMarker {
/* linkhint boxes */
background: #282828;
border: 1px solid #d65d0e;
}

div > .vimiumHintMarker span {
/* linkhint text */
color: #ebdbb2;
font-size: 13px;
}

div > .vimiumHintMarker > .matchingCharacter {
}

div.internal-vimium-hint-marker {
padding: 1px 3px;
border-radius: 0px;
}

div.internal-vimium-hint-marker span {
font-family: JetBrainsMonoNL NFP;
font-weight: normal;
}
